import { FilterSegmentVariables } from './filter-segment-variables';
import { NewInclude } from './new-include';
export interface NewFilterSegment {
    /**
     * Description of the filter-segment.
     */
    description?: string;
    /**
     * Optional unique identifier of the filter-segment. Used for Dynatrace Configuration as Code
     */
    externalId?: string;
    /**
     * List of includes of the filter-segment.
     */
    includes?: NewInclude[];
    /**
     * Indicates if the filter-segment is publicly accessible within the tenant.
     */
    isPublic: boolean;
    /**
     * Name of the filter-segment.
     */
    name: string;
    /**
     * Variables of the filter-segment.
     */
    variables?: FilterSegmentVariables;
}
